    std::string markdown = "# Heading\n\n* Bold text\n\n- Emphasized text\n\n+ List\n    - Item 1\n    - Item 2\n";
    std::string html = markdownToHtml(markdown);

    std::cout << "HTML output:\n" << html << std::endl;

    return 0;
}
```

